const fileUrl = "http://tmpfiles.org/dl/4803544/fresh.wav"

// Step 2: Call Whisper API
const token = "hf_xxx";
const baseUrl = "https://daviduk2025-whisper-stt-api.hf.space/gradio_api/call/predict";

const postResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: baseUrl,
  headers: {
    'Content-Type': 'application/json',
    'Authorization': `Bearer ${token}`
  },
  body: {
    data: [{
      path: fileUrl,
      meta: { _type: "gradio.FileData" }
    }]
  },
  json: true
});

const eventId = postResponse.event_id;

// Step 3: Wait longer for processing (5 seconds)
await new Promise(resolve => setTimeout(resolve, 5000));

// Step 4: Get transcription result
const getResponse = await this.helpers.httpRequest({
  method: 'GET',
  url: `${baseUrl}/${eventId}`,
  headers: {
    'Authorization': `Bearer ${token}`
  }
});

// Step 5: Parse the streaming response
const lines = getResponse.split('\n');
let transcription = '';
let rawResponse = getResponse; // Keep for debugging

for (const line of lines) {
  if (line.startsWith('data: ')) {
    try {
      const data = JSON.parse(line.substring(6));
      if (Array.isArray(data) && data.length > 0) {
        transcription = data[0];
      }
    } catch (e) {}
  }
}

// Return with debug info
return [{
  json: {
    content: transcription,
    type: 'audio',
    // duration: audioFile.duration,
    // from: telegramData.message.from.first_name,
    // user_id: telegramData.message.from.id,
    // chat_id: telegramData.message.chat.id,
    // message_id: telegramData.message.message_id,
    file_url: fileUrl,
    debug_raw_response: rawResponse,
    debug_event_id: eventId
  }
}];



















