const telegramData = $input.first().json;

if (!telegramData.message?.voice && !telegramData.message?.audio) {
  throw new Error('No audio file found in Telegram message');
}

const audioFile = telegramData.message.voice || telegramData.message.audio;
const fileId = audioFile.file_id;
const telegramToken = "8092334198:AAFDPTVmaasrpdvakkBT2wRWTQqlvYS758c";

// 1️⃣ Get Telegram file path
const fileInfo = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://api.telegram.org/bot${telegramToken}/getFile?file_id=${fileId}`,
  json: true
});

const filePath = fileInfo.result.file_path;
const downloadUrl = `https://api.telegram.org/file/bot${telegramToken}/${filePath}`;

// 2️⃣ Download binary
let fileBinaryRaw = await this.helpers.httpRequest({
  method: 'GET',
  url: downloadUrl,
  encoding: null,
  json: false
});

// 3️⃣ Convert to Buffer
const fileBuffer = Buffer.isBuffer(fileBinaryRaw)
  ? fileBinaryRaw
  : Buffer.from(fileBinaryRaw);

// 4️⃣ Prepare n8n binary data
const binaryData = await this.helpers.prepareBinaryData(fileBuffer, audioFile.file_unique_id + '.ogg');

// 5️⃣ Return for Google Drive node
return [{
  binary: { data: binaryData },
  json: { telegram_file_url: downloadUrl }
}];
